// Accessory keywords to block
const BLOCK = [
  'case', 'cover', 'charger', 'cable', 'adapter',
  'screen guard', 'tempered glass', 'protector',
  'stand', 'holder', 'mount', 'skin', 'sticker',
  'pouch', 'sleeve', 'earphone', 'headphone',
  'airpods', 'earbud', 'lanyard', 'power bank',
  'memory card', 'back cover', 'bumper', 'folio',
  'popsocket', 'privacy screen', 'ring light'
];

function isAccessory(title) {
  return BLOCK.some(kw => title.toLowerCase().includes(kw));
}

function parsePrice(v) {
  return parseFloat(String(v || 0).replace(/[^0-9.]/g, '')) || 0;
}

// Get shopping results from SearchAPI
const serpBody = $input.first().json;
const rows     = serpBody.shopping_results || [];

if (rows.length === 0) {
  return [{ json: { data: [], debug: { keys: Object.keys(serpBody), error: serpBody.error } } }];
}

const results = [];

for (const r of rows) {
  const title  = (r.title || '').trim();
  const price  = r.extracted_price || parsePrice(r.price);
  const source = r.seller || r.source || 'Online Store';

  if (!price || !title) continue;
  if (isAccessory(title)) continue;

  results.push({
    title,
    price,
    priceFmt: '\u20b9' + price.toLocaleString('en-IN'),
    currency:  r.currency || 'INR',
    source:    source,
    link:      r.product_link || r.link || r.offers_link || '',
    image:     r.thumbnail || '',
    rating:    r.rating  || null,
    reviews:   r.reviews || null,
    delivery:  r.delivery_return || r.delivery || '',
  });
}

// Sort by price ascending (default)
results.sort((a, b) => a.price - b.price);

// Deduplicate
const seen = new Set();
const deduped = results.filter(r => {
  const key = `${r.source}||${r.title.slice(0, 40)}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const best = deduped[0]?.price || 0;
const data = deduped.map((r, i) => ({
  ...r,
  badge:  i === 0 ? 'Best Price' : `#${i + 1}`,
  saving: i === 0 ? 0 : Math.abs(r.price - best),
}));

return [{ json: { data } }];
